using System.ComponentModel.DataAnnotations;

namespace sv_18a5644c3a9e4b5cbd4d997d7b339d81.Models;

public class AppointmentFormModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone is required.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2
    [Required(ErrorMessage = "Preferred doctor is required.")]
    public string Doctor { get; set; } = string.Empty;

    [Required(ErrorMessage = "Date is required.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Time slot is required.")]
    public string TimeSlot { get; set; } = string.Empty;

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
    public string ReasonForVisit { get; set; } = string.Empty;
}

public class PatientValidationResult
{
    public bool IsValid => Errors.Count == 0;
    public Dictionary<string, string> Errors { get; set; } = new();
}

using sv_18a5644c3a9e4b5cbd4d997d7b339d81.Models;

namespace sv_18a5644c3a9e4b5cbd4d997d7b339d81.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors =
        ["Dr. Smith", "Dr. Johnson", "Dr. Williams", "Dr. Brown"];

    private static readonly List<string> InsuranceProviders =
        ["Aetna", "BlueCross", "Cigna", "UnitedHealth", "None"];

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>(Doctors));
    }

    public Task<List<string>> GetInsuranceProvidersAsync()
    {
        return Task.FromResult(new List<string>(InsuranceProviders));
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return fixed time slots regardless of doctor/date
        var slots = new List<string>
        {
            "9:00 AM", "9:30 AM", "10:00 AM", "10:30 AM",
            "11:00 AM", "1:00 PM", "1:30 PM", "2:00 PM",
            "2:30 PM", "3:00 PM", "3:30 PM", "4:00 PM"
        };
        return Task.FromResult(slots);
    }

    public Task<PatientValidationResult> ValidatePatientAsync(AppointmentFormModel model)
    {
        var result = new PatientValidationResult();

        // Reject "taken@example.com" for outstanding balance
        if (string.Equals(model.Email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors[nameof(model.Email)] = "Account has outstanding balance";
        }

        // Reject "None" insurance with "Dr. Smith"
        if (model.InsuranceProvider == "None"
            && string.Equals(model.Doctor, "Dr. Smith", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors[nameof(model.Doctor)] = "Selected doctor does not accept self-pay patients";
        }

        // Reject "10:00 AM" as already taken
        if (model.TimeSlot == "10:00 AM")
        {
            result.Errors[nameof(model.TimeSlot)] = "This slot is no longer available";
        }

        return Task.FromResult(result);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_18a5644c3a9e4b5cbd4d997d7b339d81.Models
@using sv_18a5644c3a9e4b5cbd4d997d7b339d81.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book a Medical Appointment</h3>

<EditForm Model="formModel" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* ───── STEP 1 ───── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="formModel.PatientName" />
            <ValidationMessage For="() => formModel.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="formModel.Email" />
            <ValidationMessage For="() => formModel.Email" />
            @if (serverErrors.ContainsKey(nameof(formModel.Email)))
            {
                <div class="validation-message">@serverErrors[nameof(formModel.Email)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="formModel.Phone" />
            <ValidationMessage For="() => formModel.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="formModel.InsuranceProvider">
                <option value="">-- Select --</option>
                @foreach (var provider in insuranceProviders)
                {
                    <option value="@provider">@provider</option>
                }
            </InputSelect>
            <ValidationMessage For="() => formModel.InsuranceProvider" />
        </div>
    </fieldset>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
            Next
        </button>
    }

    @* ───── STEP 2 ───── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="formModel.Doctor">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => formModel.Doctor" />
                @if (serverErrors.ContainsKey(nameof(formModel.Doctor)))
                {
                    <div class="validation-message">@serverErrors[nameof(formModel.Doctor)]</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="formModel.AppointmentDate"
                           @bind-Value:after="OnDateChanged" />
                <ValidationMessage For="() => formModel.AppointmentDate" />
                @if (dateError is not null)
                {
                    <div class="validation-message">@dateError</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeSlot">Time Slot</label>
                <InputSelect id="timeSlot" class="form-select" @bind-Value="formModel.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => formModel.TimeSlot" />
                @if (serverErrors.ContainsKey(nameof(formModel.TimeSlot)))
                {
                    <div class="validation-message">@serverErrors[nameof(formModel.TimeSlot)]</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" @bind-Value="formModel.ReasonForVisit" rows="3" />
                <ValidationMessage For="() => formModel.ReasonForVisit" />
            </div>

            <div class="d-flex gap-2">
                <button type="button" class="btn btn-secondary" @onclick="BackToStep1">
                    Back
                </button>
                <button type="button" class="btn btn-info" @onclick="CheckAvailability" disabled="@isChecking">
                    @(isChecking ? "Checking…" : "Check Availability")
                </button>
                @if (availabilityConfirmed)
                {
                    <button type="submit" class="btn btn-success">
                        Book Appointment
                    </button>
                }
            </div>
        </fieldset>
    }
</EditForm>

@if (bookingConfirmed)
{
    <div class="alert alert-success mt-4" role="alert">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentFormModel formModel = new();
    private EditContext? editContext;

    private List<string> insuranceProviders = [];
    private List<string> doctors = [];
    private List<string> availableSlots = [];

    private Dictionary<string, string> serverErrors = new();
    private string? dateError;

    private bool showStep2;
    private bool isChecking;
    private bool availabilityConfirmed;
    private bool bookingConfirmed;

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(formModel);
        insuranceProviders = await AppointmentService.GetInsuranceProvidersAsync();
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(formModel);
        // Validate only step-1 fields
        var isValid = true;
        var messageStore = new ValidationMessageStore(editContext);

        if (string.IsNullOrWhiteSpace(formModel.PatientName))
        {
            messageStore.Add(() => formModel.PatientName, "Patient name is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(formModel.Email))
        {
            messageStore.Add(() => formModel.Email, "Email is required.");
            isValid = false;
        }
        else if (!new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(formModel.Email))
        {
            messageStore.Add(() => formModel.Email, "Invalid email format.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(formModel.Phone))
        {
            messageStore.Add(() => formModel.Phone, "Phone is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(formModel.InsuranceProvider))
        {
            messageStore.Add(() => formModel.InsuranceProvider, "Insurance provider is required.");
            isValid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (isValid)
        {
            showStep2 = true;
            serverErrors.Clear();
            availabilityConfirmed = false;
        }
    }

    private async Task OnDateChanged()
    {
        dateError = null;
        availableSlots.Clear();
        formModel.TimeSlot = string.Empty;
        availabilityConfirmed = false;
        serverErrors.Remove(nameof(formModel.TimeSlot));

        if (formModel.AppointmentDate is not null)
        {
            if (formModel.AppointmentDate <= DateOnly.FromDateTime(DateTime.Today))
            {
                dateError = "Date must be in the future.";
                return;
            }

            if (!string.IsNullOrEmpty(formModel.Doctor))
            {
                availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                    formModel.Doctor, formModel.AppointmentDate.Value);
            }
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        dateError = null;
        availabilityConfirmed = false;

        // Client-side step-2 validation
        var valid = true;

        if (string.IsNullOrWhiteSpace(formModel.Doctor))
        {
            serverErrors[nameof(formModel.Doctor)] = "Preferred doctor is required.";
            valid = false;
        }
        if (formModel.AppointmentDate is null)
        {
            dateError = "Date is required.";
            valid = false;
        }
        else if (formModel.AppointmentDate <= DateOnly.FromDateTime(DateTime.Today))
        {
            dateError = "Date must be in the future.";
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(formModel.TimeSlot))
        {
            serverErrors[nameof(formModel.TimeSlot)] = "Time slot is required.";
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(formModel.ReasonForVisit))
        {
            serverErrors[nameof(formModel.ReasonForVisit)] = "Reason for visit is required.";
            valid = false;
        }
        else if (formModel.ReasonForVisit.Length > 500)
        {
            serverErrors[nameof(formModel.ReasonForVisit)] = "Reason must be 500 characters or fewer.";
            valid = false;
        }

        if (!valid) return;

        isChecking = true;
        try
        {
            var result = await AppointmentService.ValidatePatientAsync(formModel);
            if (!result.IsValid)
            {
                foreach (var err in result.Errors)
                {
                    serverErrors[err.Key] = err.Value;
                }
            }
            else
            {
                availabilityConfirmed = true;
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        serverErrors.Clear();
        dateError = null;
        availabilityConfirmed = false;
    }

    private void HandleSubmit()
    {
        if (!availabilityConfirmed) return;
        bookingConfirmed = true;
    }
}

