+            messageStore.Add(() => formModel.PatientName, "Patient name is required.");
+            isValid = false;
+        }
+        if (string.IsNullOrWhiteSpace(formModel.Email))
+        {
+            messageStore.Add(() => formModel.Email, "Email is required.");
+            isValid = false;
+        }
+        else if (!new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(formModel.Email))
+        {
+            messageStore.Add(() => formModel.Email, "Invalid email format.");
+            isValid = false;
+        }
+        if (string.IsNullOrWhiteSpace(formModel.Phone))
+        {
+            messageStore.Add(() => formModel.Phone, "Phone is required.");
+            isValid = false;
+        }
+        if (string.IsNullOrWhiteSpace(formModel.InsuranceProvider))
+        {
+            messageStore.Add(() => formModel.InsuranceProvider, "Insurance provider is required.");
+            isValid = false;
+        }
+
+        editContext.NotifyValidationStateChanged();
+
+        if (isValid)
+        {
+            showStep2 = true;
+            serverErrors.Clear();
+            availabilityConfirmed = false;
+        }
+    }
+
+    private async Task OnDateChanged()
+    {
+        dateError = null;
+        availableSlots.Clear();
+        formModel.TimeSlot = string.Empty;
+        availabilityConfirmed = false;
+        serverErrors.Remove(nameof(formModel.TimeSlot));
+
+        if (formModel.AppointmentDate is not null)
+        {
+            if (formModel.AppointmentDate <= DateOnly.FromDateTime(DateTime.Today))
+            {
+                dateError = "Date must be in the future.";
+                return;
+            }
+
+            if (!string.IsNullOrEmpty(formModel.Doctor))
+            {
+                availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
+                    formModel.Doctor, formModel.AppointmentDate.Value);
+            }
+        }
+    }
+
+    private async Task CheckAvailability()
+    {
+        serverErrors.Clear();
+        dateError = null;
+        availabilityConfirmed = false;
+
+        // Client-side step-2 validation
+        var valid = true;
+
+        if (string.IsNullOrWhiteSpace(formModel.Doctor))
+        {
+            serverErrors[nameof(formModel.Doctor)] = "Preferred doctor is required.";
+            valid = false;
+        }
+        if (formModel.AppointmentDate is null)
+        {
+            dateError = "Date is required.";
+            valid = false;
+        }
+        else if (formModel.AppointmentDate <= DateOnly.FromDateTime(DateTime.Today))
+        {
+            dateError = "Date must be in the future.";
+            valid = false;
+        }
+        if (string.IsNullOrWhiteSpace(formModel.TimeSlot))
+        {
+            serverErrors[nameof(formModel.TimeSlot)] = "Time slot is required.";
+            valid = false;
+        }
+        if (string.IsNullOrWhiteSpace(formModel.ReasonForVisit))
+        {
+            serverErrors[nameof(formModel.ReasonForVisit)] = "Reason for visit is required.";
+            valid = false;
+        }
+        else if (formModel.ReasonForVisit.Length > 500)
+        {
+            serverErrors[nameof(formModel.ReasonForVisit)] = "Reason must be 500 characters or fewer.";
+            valid = false;
+        }
+
+        if (!valid) return;
+
+        isChecking = true;
+        try
+        {
+            var result = await AppointmentService.ValidatePatientAsync(formModel);
+            if (!result.IsValid)
+            {
+                foreach (var err in result.Errors)
+                {
+                    serverErrors[err.Key] = err.Value;
+                }
+            }
+            else
+            {
+                availabilityConfirmed = true;
+            }
+        }
+        finally
+        {
+            isChecking = false;
+        }
+    }
+
+    private void BackToStep1()
+    {
+        showStep2 = false;
+        serverErrors.Clear();
+        dateError = null;
+        availabilityConfirmed = false;
+    }
+
+    private void HandleSubmit()
+    {
+        if (!availabilityConfirmed) return;
+        bookingConfirmed = true;
+    }
+}
